     1→/**
     2→ * Organiza line breakers para padronizar código e facilitar code review.
     3→ */
     4→
     5→import { doc } from 'prettier';
     6→import * as estreePlugin from 'prettier/plugins/estree';
     7→
     8→const estreePrinters = estreePlugin.printers;
     9→
    10→const originalEstreePrinter = estreePrinters.estree;
    11→const { group, indent, line, softline, join, ifBreak } = doc.builders;
    12→
    13→const DEFAULT_THRESHOLD = 1;
    14→const DEFAULT_CONDITION_PRINT_WIDTH = 50;
    15→
    16→const FUNCTION_NODE_TYPES = new Set([
    17→  'FunctionDeclaration',
    18→  'FunctionExpression',
    19→  'ArrowFunctionExpression',
    20→  'ObjectMethod',
    21→  'ClassMethod',
    22→  'TSDeclareMethod',
    23→  'TSFunctionType',
    24→  'TSMethodSignature',
    25→]);
    26→
    27→const TYPE_ASSERTION_TYPES = new Set([
    28→  'TSAsExpression',
    29→  'TSTypeAssertion',
    30→]);
    31→
    32→function isArrowBodyObject(path) {
    33→  const parent = path.getParentNode();
    34→  return (
    35→    parent?.type === 'ArrowFunctionExpression' &&
    36→    parent.body === path.getValue()
    37→  );
    38→}
    39→
    40→function isArrowBodyTypeAssertion(path) {
    41→  const node = path.getValue();
    42→  const parent = path.getParentNode();
    43→
    44→  if (parent?.type !== 'ArrowFunctionExpression' || parent.body !== node) {
    45→    return false;
    46→  }
    47→
    48→  let current = node;
    49→  while (TYPE_ASSERTION_TYPES.has(current?.type)) {
    50→    current = current.expression;
    51→  }
    52→
    53→  return current?.type === 'ObjectExpression';
    54→}
    55→
    56→function asInt(value, defaultValue) {
    57→  const num = parseInt(String(value), 10);
    58→  if (!Number.isNaN(num) && num >= 0) {
    59→    return num;
    60→  }
    61→  return defaultValue;
    62→}
    63→
    64→function createWrappedPrinter(originalPrinter) {
    65→  return {
    66→    ...originalPrinter,
    67→    print(path, options, print) {
    68→      const node = path.getValue();
    69→
    70→      const getText = () => {
    71→        if (!node.range || !options.originalText) return '';
    72→        return options.originalText.slice(node.range[0], node.range[1]);
    73→      };
    74→
    75→      const multilineWrapThreshold = asInt(
    76→        options.multilineWrapThreshold,
    77→        DEFAULT_THRESHOLD,
    78→      );
    79→      const objectWrapThreshold = asInt(
    80→        options.objectWrapThreshold,
    81→        multilineWrapThreshold,
    82→      );
    83→      const arrayWrapThreshold = asInt(
    84→        options.arrayWrapThreshold,
    85→        objectWrapThreshold,
    86→      );
    87→      const paramsPrintWidth = asInt(
    88→        options.paramsPrintWidth,
    89→        DEFAULT_CONDITION_PRINT_WIDTH,
    90→      );
    91→
    92→      const trailingComma =
    93→        options.trailingComma === 'all' || options.trailingComma === 'es5'
    94→          ? ifBreak(',', '')
    95→          : '';
    96→
    97→      if (
    98→        node?.type === 'IfStatement' &&
    99→        node.consequent &&
   100→        node.consequent.type !== 'BlockStatement' &&
   101→        getText().split(')')[0].length > paramsPrintWidth
   102→      ) {
   103→        const parts = [
   104→          'if (',
   105→          softline,
   106→          path.call(print, 'test'),
   107→          softline,
   108→          ') ',
   109→          '{',
   110→          indent([
   111→            line,
   112→            path.call(print, 'consequent'),
   113→          ]),
   114→          line,
   115→          '}',
   116→        ];
   117→
   118→        if (node.alternate) {
   119→          parts.push(' else ', path.call(print, 'alternate'));
   120→        }
   121→
   122→        return parts;
   123→      }
   124→
   125→      if (
   126→        TYPE_ASSERTION_TYPES.has(node?.type) &&
   127→        isArrowBodyTypeAssertion(path)
   128→      ) {
   129→        return [
   130→          '(',
   131→          originalPrinter.print(path, options, print),
   132→          ')',
   133→        ];
   134→      }
   135→
   136→      if (
   137→        node?.type === 'ArrayExpression' &&
   138→        node.elements &&
   139→        node.elements.length > arrayWrapThreshold
   140→      ) {
   141→        return group(
   142→          [
   143→            '[',
   144→            indent([
   145→              line,
   146→              join(
   147→                [
   148→                  ',',
   149→                  line,
   150→                ],
   151→                path.map(print, 'elements'),
   152→              ),
   153→              trailingComma,
   154→            ]),
   155→            line,
   156→            ']',
   157→          ],
   158→          { shouldBreak: true },
   159→        );
   160→      }
   161→
   162→      if (
   163→        node?.type === 'ObjectExpression' &&
   164→        node.properties &&
   165→        node.properties.length > objectWrapThreshold
   166→      ) {
   167→        const objectDoc = group(
   168→          [
   169→            '{',
   170→            indent([
   171→              line,
   172→              join(
   173→                [
   174→                  ',',
   175→                  line,
   176→                ],
   177→                path.map(print, 'properties'),
   178→              ),
   179→              trailingComma,
   180→            ]),
   181→            line,
   182→            '}',
   183→          ],
   184→          { shouldBreak: true },
   185→        );
   186→
   187→        if (isArrowBodyObject(path)) {
   188→          return [
   189→            '(',
   190→            objectDoc,
   191→            ')',
   192→          ];
   193→        }
   194→
   195→        return objectDoc;
   196→      }
   197→
   198→      if (
   199→        node?.type === 'TSTypeLiteral' &&
   200→        node.members &&
   201→        node.members.length > objectWrapThreshold
   202→      ) {
   203→        return group(
   204→          [
   205→            '{',
   206→            indent([
   207→              line,
   208→              join(line, path.map(print, 'members')),
   209→            ]),
   210→            line,
   211→            '}',
   212→          ],
   213→          {
   214→            shouldBreak: true,
   215→          },
   216→        );
   217→      }
   218→
   219→      const shouldBreakParams =
   220→        FUNCTION_NODE_TYPES.has(node?.type) &&
   221→        node.params &&
   222→        node.params.length > 3;
   223→
   224→      if (shouldBreakParams) {
   225→        const result = [];
   226→
   227→        if (
   228→          node.type === 'ClassMethod' ||
   229→          node.type === 'ObjectMethod' ||
   230→          node.type === 'TSDeclareMethod'
   231→        ) {
   232→          if (node.static) result.push('static ');
   233→          if (node.accessibility) result.push(node.accessibility, ' ');
   234→          if (node.abstract) result.push('abstract ');
   235→          if (node.kind === 'get' || node.kind === 'set') {
   236→            result.push(node.kind, ' ');
   237→          }
   238→        }
   239→
   240→        if (node.async) {
   241→          result.push('async ');
   242→        }
   243→
   244→        if (
   245→          node.type === 'FunctionDeclaration' ||
   246→          node.type === 'FunctionExpression'
   247→        ) {
   248→          if (getText().match(/^(async )?function/)) {
   249→            result.push('function');
   250→          }
   251→
   252→          if (node.generator) {
   253→            result.push('*');
   254→          }
   255→          if (node.id) {
   256→            result.push(' ', path.call(print, 'id'));
   257→          }
   258→        } else if (node.key) {
   259→          result.push(path.call(print, 'key'));
   260→        }
   261→
   262→        if (node.typeParameters) {
   263→          result.push(path.call(print, 'typeParameters'));
   264→        }
   265→
   266→        result.push(
   267→          group(
   268→            [
   269→              '(',
   270→              indent([
   271→                line,
   272→                join(
   273→                  [
   274→                    ',',
   275→                    line,
   276→                  ],
   277→                  path.map(print, 'params'),
   278→                ),
   279→              ]),
   280→              line,
   281→              ')',
   282→            ],
   283→            {
   284→              shouldBreak: true,
   285→            },
   286→          ),
   287→        );
   288→
   289→        if (node.returnType) {
   290→          result.push(path.call(print, 'returnType'));
   291→        } else if (node.predicate) {
   292→          result.push(path.call(print, 'predicate'));
   293→        }
   294→
   295→        if (node.body) {
   296→          const shouldAddBraces = node.body.type !== 'BlockStatement';
   297→
   298→          if (node.type === 'ArrowFunctionExpression') {
   299→            if (shouldAddBraces) {
   300→              result.push('=> {', line, 'return ');
   301→            } else {
   302→              result.push('=>');
   303→            }
   304→          }
   305→
   306→          result.push(' ', path.call(print, 'body'));
   307→          if (shouldAddBraces) {
   308→            result.push(line, '}', line);
   309→          }
   310→        }
   311→
   312→        return result;
   313→      }
   314→
   315→      return originalPrinter.print(path, options, print);
   316→    },
   317→  };
   318→}
   319→
   320→const plugin = {
   321→  printers: {
   322→    estree: createWrappedPrinter(originalEstreePrinter),
   323→  },
   324→};
   325→
   326→export const printers = plugin.printers;
   327→

